import{_ as t,o,c as r,a2 as a}from"./chunks/framework.B08aFN1B.js";const p=JSON.parse('{"title":"Remotes & Worker Pools","description":"","frontmatter":{},"headers":[],"relativePath":"remotes.md","filePath":"remotes.md","lastUpdated":null}'),s={name:"remotes.md"};function n(l,e,i,h,d,c){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="Remotes-and-Worker-Pools" tabindex="-1">Remotes &amp; Worker Pools <a class="header-anchor" href="#Remotes-and-Worker-Pools" aria-label="Permalink to &quot;Remotes &amp; Worker Pools {#Remotes-and-Worker-Pools}&quot;">​</a></h1><p>A notebook&#39;s <strong>worker</strong> — the Julia process that evaluates its cells — normally runs on your machine. It can just as easily run on <strong>another machine</strong>: a beefy workstation, a GPU box, a cloud VM. Reactivity, hot-reload, package management, figures, and streaming all stay transparent — the notebook behaves exactly as if it were local; only the compute moves.</p><p>Each notebook is placed <strong>independently</strong>, so one can run locally while another runs on a remote host, each in its own worker.</p><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><p>A remote is any <strong>SSH host you already reach with key auth</strong> — a <code>Host</code> entry in <code>~/.ssh/config</code> (or a <code>user@host</code> you can <code>ssh</code> to without a password prompt). KaimonSlate provisions the rest: it checks the host, ensures a Julia + environment is present, and starts the worker for you.</p><h2 id="Set-up-a-host-—-Remotes" tabindex="-1">Set up a host — 🖧 Remotes <a class="header-anchor" href="#Set-up-a-host-—-Remotes" aria-label="Permalink to &quot;Set up a host — 🖧 Remotes {#Set-up-a-host-—-Remotes}&quot;">​</a></h2><p>On the hub&#39;s <a href="/KaimonSlate.jl/dev/getting-started#the-front-page">front page</a>, click <strong>🖧 Remotes</strong> to add and test a host:</p><ul><li><p><strong>Host</strong> — the SSH target (<code>my-workstation</code>, or <code>user@host</code>).</p></li><li><p><strong>Transport</strong> — how the notebook talks to the worker:</p><ul><li><p><strong>SSH tunnel</strong> (default) — traffic is forwarded over the SSH connection. Works anywhere <code>ssh</code> works, opens no extra ports, needs no firewall changes. The safe default.</p></li><li><p><strong>Direct · CURVE</strong> — encrypted ZeroMQ sockets straight to the host (CurveZMQ). Lower overhead, and it&#39;s what enables the <strong>data channel</strong> that carries your cache (see <a href="/KaimonSlate.jl/dev/remotes#your-cache-follows-you">below</a>). Needs the worker&#39;s ports reachable through any firewall — pin them under <strong>Ports</strong> (blank = auto, <code>9100+</code>) and open them on the host.</p></li></ul></li><li><p><strong>🩺 Test &amp; prime</strong> — a full reported dry-run: SSH reachability, Julia presence (+ version), environment provisioning, gate load, a CURVE key (for <code>direct</code>), then a real spawn → connect → round-trip eval → clean teardown. It returns a step-by-step checklist <strong>and primes the host</strong>, so the first real notebook run is fast (cold provisioning happens here, once).</p></li></ul><div class="tip custom-block"><p class="custom-block-title">Run the preflight first</p><p>Always <strong>Test &amp; prime</strong> a new host before running a notebook on it — it catches setup problems (missing Julia, closed ports, key auth) with a clear checklist instead of a stuck worker, and warms the host so the first real run doesn&#39;t pay provisioning time.</p></div><h2 id="Run-a-notebook-on-a-remote" tabindex="-1">Run a notebook on a remote <a class="header-anchor" href="#Run-a-notebook-on-a-remote" aria-label="Permalink to &quot;Run a notebook on a remote {#Run-a-notebook-on-a-remote}&quot;">​</a></h2><p>Two ways to place a notebook&#39;s worker:</p><ul><li><p><strong>When you open it</strong> — the front page&#39;s <strong>Run on</strong> selector (next to Open / ⬆ Upload) picks <em>local</em> or a configured host before the notebook opens.</p></li><li><p><strong>On a live notebook</strong> — switch it any time; the worker moves and the notebook re-runs.</p></li></ul><p>Placement has a <strong>scope</strong>, so you control how sticky it is:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Scope</th><th style="text-align:right;">Meaning</th></tr></thead><tbody><tr><td style="text-align:right;"><strong>session</strong></td><td style="text-align:right;">This session only — not saved. The default.</td></tr><tr><td style="text-align:right;"><strong>notebook</strong></td><td style="text-align:right;">Durable — saved in the <code>.jl</code> so the notebook <strong>reopens on that host</strong>.</td></tr><tr><td style="text-align:right;"><strong>clear</strong></td><td style="text-align:right;">Drop the overrides and fall back to the global default / local.</td></tr></tbody></table><h2 id="Warm-pools" tabindex="-1">Warm pools <a class="header-anchor" href="#Warm-pools" aria-label="Permalink to &quot;Warm pools {#Warm-pools}&quot;">​</a></h2><p>A cold remote worker pays a one-time boot (provision + start Julia + load packages) that can be ~90 s. A <strong>warm pool</strong> removes that wait: keep a few prewarmed workers idling on a host, and opening a matching notebook <strong>adopts</strong> one in about a second.</p><ul><li><p><strong><code>warm_pool(host; n, preload)</code></strong> — keep <code>n</code> prewarmed workers on <code>host</code>. Each is a booted Julia process with the gate serving and the eval path warmed; <code>preload</code> (a local project directory) additionally replicates that environment on the host and imports its packages while idle. Opening a notebook whose project matches <code>preload</code> then <strong>adopts</strong> a pool worker (dial + namespace swap — packages and cache survive) instead of cold-booting, and the pool refills itself in the background. <code>n=0</code> drains idle pool workers (attached workers are never touched). Safe to re-run — it reconciles toward <code>n</code>.</p></li><li><p><strong><code>pools()</code></strong> — the hub&#39;s view: every configured pool (host, target size, preload env, transport) and every <strong>parked wire</strong> (a live connection kept across a notebook close for instant reattach).</p></li><li><p><strong><code>remote_workers(host)</code></strong> — a host&#39;s live roster: which notebook each worker serves, its state (attached / idle / pool), telemetry (cpu / rss / cache size), and whether it looks abandoned.</p></li><li><p><strong><code>reap_worker(host, port)</code></strong> — explicitly kill one worker and remove its files. Manual only — nothing is auto-reaped, so a worker holding useful results is safe until you remove it.</p></li><li><p><strong><code>whereis(notebook)</code></strong> — where a given notebook runs right now (local pid/port or remote host), with transport, ports, connection state, and pool provenance.</p></li></ul><h2 id="Your-cache-follows-you" tabindex="-1">Your cache follows you <a class="header-anchor" href="#Your-cache-follows-you" aria-label="Permalink to &quot;Your cache follows you {#Your-cache-follows-you}&quot;">​</a></h2><p>KaimonSlate&#39;s <a href="/KaimonSlate.jl/dev/cell-tags#caching">durable cache</a> can move to the remote so it <strong>restores</strong> cached results there instead of recomputing them — &quot;your session follows you.&quot;</p><ul><li><p><strong>On attach</strong>, cached results are carried over automatically <strong>when moving them beats recomputing</strong> — and never if a single entry would take longer than the <strong>carry-time budget</strong> to transfer (that cell just recomputes remotely instead).</p></li><li><p><strong><code>sync_memo(notebook)</code></strong> pushes <strong>everything</strong> — all of the notebook&#39;s local cache blobs — to the remote, deduping against what it already has. Requires a <strong><code>direct</code></strong>-transport worker (the cache rides the CURVE data channel, gate port + 2).</p></li></ul><p>Tune the transfer under <strong>🖧 Remotes → Data transfer</strong> (applies to all notebooks):</p><table tabindex="0"><thead><tr><th style="text-align:right;">Setting</th><th style="text-align:right;">Effect</th></tr></thead><tbody><tr><td style="text-align:right;"><strong>Transfer chunk size</strong></td><td style="text-align:right;">MB moved per round-trip. Transfers ride their own channel, so this never delays cell results — smaller chunks bound per-chunk timeouts and let an abort land sooner on a slow uplink; bigger ones move data faster on a good link.</td></tr><tr><td style="text-align:right;"><strong>Carry-time budget</strong></td><td style="text-align:right;">On attach, an entry is only carried if moving it is worth it and it fits in this budget; otherwise the cell recomputes. (<code>sync_memo</code> ignores this — it always pushes everything.)</td></tr><tr><td style="text-align:right;"><strong>Confirm transfers over</strong></td><td style="text-align:right;">When a cell needs a value that must cross the network, it pauses with an exact size + estimated-time preview if the transfer would take longer than this; run the cell again to proceed. <code>0</code> never asks.</td></tr></tbody></table><h2 id="From-the-agent" tabindex="-1">From the agent <a class="header-anchor" href="#From-the-agent" aria-label="Permalink to &quot;From the agent {#From-the-agent}&quot;">​</a></h2><p>Under <a href="./agent">Kaimon</a>, the agent drives all of this through <code>slate.*</code> tools — each one&#39;s schema has the full parameters (<code>slate_api(&quot;remote&quot;)</code> lists them):</p><table tabindex="0"><thead><tr><th style="text-align:right;">Tool</th><th style="text-align:right;">Does</th></tr></thead><tbody><tr><td style="text-align:right;"><code>slate_run_on(notebook, host, scope)</code></td><td style="text-align:right;">Place a notebook&#39;s worker (local / SSH host; transport; scope).</td></tr><tr><td style="text-align:right;"><code>slate_check_remote(host, transport)</code></td><td style="text-align:right;">Preflight + prime a host (the <strong>Test &amp; prime</strong> dry-run).</td></tr><tr><td style="text-align:right;"><code>slate_warm_pool(host; n, preload)</code></td><td style="text-align:right;">Maintain a warm pool for instant adoption.</td></tr><tr><td style="text-align:right;"><code>slate_pools()</code></td><td style="text-align:right;">Configured pools + parked wires (the hub view).</td></tr><tr><td style="text-align:right;"><code>slate_remote_workers(host)</code></td><td style="text-align:right;">A host&#39;s live worker roster + telemetry.</td></tr><tr><td style="text-align:right;"><code>slate_reap_worker(host, port)</code></td><td style="text-align:right;">Kill and remove one remote worker.</td></tr><tr><td style="text-align:right;"><code>slate_whereis(notebook)</code></td><td style="text-align:right;">Where a notebook runs right now.</td></tr><tr><td style="text-align:right;"><code>slate_sync_memo(notebook)</code></td><td style="text-align:right;">Push the notebook&#39;s full cache to a <code>direct</code> remote.</td></tr></tbody></table><h2 id="See-also" tabindex="-1">See also <a class="header-anchor" href="#See-also" aria-label="Permalink to &quot;See also {#See-also}&quot;">​</a></h2><ul><li><p><a href="./configuration">Configuration</a> — hub port, kernel selection, environment variables.</p></li><li><p><a href="./cell-tags">Cell Tags &amp; Caching</a> — the durable cache that <code>sync_memo</code> moves.</p></li><li><p><a href="./packages">Packages</a> — a notebook&#39;s per-project environment (what <code>preload</code> replicates).</p></li></ul>',27)])])}const u=t(s,[["render",n]]);export{p as __pageData,u as default};
